#include <stdatomic.h>

typedef struct {
    atomic_flag lock;
} SpinLock;

void spin_lock_init(SpinLock *sl) {
    atomic_flag_clear(&sl->lock);
}

void spin_lock(SpinLock *sl) {
    while (atomic_flag_test_and_set(&sl->lock) == true) {
        // Busy wait - spin
    }
}

void spin_unlock(SpinLock *sl) {
    atomic_flag_clear(&sl->lock);
}

// Usage in critical section
SpinLock myLock;

void process_function() {
    spin_lock(&myLock);
    // Critical section - shared resources accessed
    spin_unlock(&myLock);
    // Remainder section
}

#include <semaphore.h>
#include <pthread.h>

#define BUFFER_SIZE 10

int buffer[BUFFER_SIZE];
int in = 0, out = 0;

sem_t empty;  // Counts empty slots
sem_t full;   // Counts full slots
sem_t mutex;  // Binary semaphore for mutual exclusion

void *producer(void *arg) {
    int item;
    while(1) {
        item = produce_item();

        sem_wait(&empty);    // Wait for empty slot
        sem_wait(&mutex);    // Enter critical section

        buffer[in] = item;
        in = (in + 1) % BUFFER_SIZE;

        sem_post(&mutex);    // Exit critical section
        sem_post(&full);     // Signal filled slot
    }
}

void *consumer(void *arg) {
    int item;
    while(1) {
        sem_wait(&full);     // Wait for full slot
        sem_wait(&mutex);    // Enter critical section

        item = buffer[out];
        out = (out + 1) % BUFFER_SIZE;

        sem_post(&mutex);    // Exit critical section
        sem_post(&empty);    // Signal empty slot

        consume_item(item);
    }
}

int main() {
    sem_init(&empty, 0, BUFFER_SIZE);
    sem_init(&full, 0, 0);
    sem_init(&mutex, 0, 1);
    // Create producer and consumer threads
    return 0;
}
